     1→/**
     2→ * @file test-helpers.ts
     3→ *
     4→ * Shared test constants, fixture factories, and mock builders for the
     5→ * collection module test suite. All magic strings and reusable mock
     6→ * objects live here so that spec files remain declarative and DRY.
     7→ */
     8→
     9→import {
    10→    DatabaseResult,
    11→    SystemCollection,
    12→    CollectionDocumentAssociation,
    13→    CollectionDocumentPair,
    14→} from '@app/discovery-neo';
    15→import { CollectionRepository } from '@app/discovery-neo/collections/collection.repository';
    16→import { TerminologyRepository } from '@app/discovery-neo/terminologies/terminology.repository';
    17→import { AuditingService } from '@app/auditing';
    18→import { AsyncTransactionHelper } from '@app/auditing';
    19→import { CollectionService } from '../collection.service';
    20→import { CollectionController } from '../collection.controller';
    21→import { TerminologyService } from '../../terminologies/terminology.service';
    22→import { ApiService } from '../../enrichment/api.service';
    23→
    24→// ---------------------------------------------------------------------------
    25→// Semantic test constants — single source of truth for all magic values
    26→// ---------------------------------------------------------------------------
    27→
    28→/** Collection identifiers */
    29→export const COLLECTION_ID_A = 'collection-source-id-aaa';
    30→export const COLLECTION_ID_B = 'collection-source-id-bbb';
    31→
    32→/** Collection names */
    33→export const COLLECTION_NAME_A = 'Alpha Collection';
    34→export const COLLECTION_NAME_B = 'Beta Collection';
    35→
    36→/** Document / version identifiers */
    37→export const VERSION_ID_A = 'version-id-111';
    38→export const VERSION_ID_B = 'version-id-222';
    39→export const VERSION_ID_C = 'version-id-333';
    40→
    41→/** Terminology identifiers */
    42→export const TERMINOLOGY_ID_A = 'terminology-id-aaa';
    43→export const TERMINOLOGY_ID_B = 'terminology-id-bbb';
    44→
    45→/** Audit / transaction identifiers */
    46→export const AUDIT_ID = 'audit-id-xyz789';
    47→
    48→/** Error messages */
    49→export const ERROR_REPO_FAILED = 'repository operation failed';
    50→export const ERROR_INVALID_COLLECTION = `Invalid collection id supplied ${COLLECTION_ID_A}`;
    51→export const ERROR_INVALID_TERMINOLOGY = `Invalid Terminology id supplied ${COLLECTION_ID_A}`;
    52→
    53→// ---------------------------------------------------------------------------
    54→// DatabaseResult fixture factories
    55→// ---------------------------------------------------------------------------
    56→
    57→/** Creates a successful DatabaseResult wrapping arbitrary data. */
    58→export function makeDatabaseSuccess<T>(data: T): DatabaseResult<T> {
    59→    return { success: true, data };
    60→}
    61→
    62→/** Creates a failed DatabaseResult with the given error message. */
    63→export function makeDatabaseError(message: string = ERROR_REPO_FAILED): DatabaseResult<never> {
    64→    return { success: false, error: message };
    65→}
    66→
    67→/** Builds a minimal SystemCollection fixture. */
    68→export function makeSystemCollection(
    69→    overrides: Partial<SystemCollection> = {},
    70→): SystemCollection {
    71→    return {
    72→        sourceId: COLLECTION_ID_A,
    73→        name: COLLECTION_NAME_A,
    74→        ...overrides,
    75→    };
    76→}
    77→
    78→/** Builds a CollectionDocumentAssociation fixture. */
    79→export function makeCollectionDocumentAssociation(
    80→    overrides: Partial<CollectionDocumentAssociation> = {},
    81→): CollectionDocumentAssociation {
    82→    return {
    83→        collectionId: COLLECTION_ID_A,
    84→        documentId: VERSION_ID_A,
    85→        ...overrides,
    86→    };
    87→}
    88→
    89→/** Builds a CollectionDocumentPair fixture. */
    90→export function makeCollectionDocumentPair(
    91→    overrides: Partial<CollectionDocumentPair> = {},
    92→): CollectionDocumentPair {
    93→    return {
    94→        collectionId: COLLECTION_ID_A,
    95→        documentId: VERSION_ID_A,
    96→        ...overrides,
    97→    };
    98→}
    99→
   100→// ---------------------------------------------------------------------------
   101→// Mock builders
   102→// ---------------------------------------------------------------------------
   103→
   104→/**
   105→ * Builds a jest-mocked CollectionRepository with safe default return values.
   106→ * Every method resolves to a success result unless overridden by the caller.
   107→ */
   108→export function buildMockCollectionRepository(
   109→    overrides: Partial<jest.Mocked<CollectionRepository>> = {},
   110→): jest.Mocked<CollectionRepository> {
   111→    return {
   112→        createCollection: jest.fn().mockResolvedValue(
   113→            makeDatabaseSuccess({ sourceId: COLLECTION_ID_A }),
   114→        ),
   115→        updateCollection: jest.fn().mockResolvedValue(
   116→            makeDatabaseSuccess({ sourceId: COLLECTION_ID_A, terminologyId: TERMINOLOGY_ID_A }),
   117→        ),
   118→        deleteCollection: jest.fn().mockResolvedValue(
   119→            makeDatabaseSuccess({ count: 1 }),
   120→        ),
   121→        getAllCollections: jest.fn().mockResolvedValue(
   122→            makeDatabaseSuccess([makeSystemCollection()]),
   123→        ),
   124→        hasCollection: jest.fn().mockResolvedValue(
   125→            makeDatabaseSuccess({ exists: true }),
   126→        ),
   127→        associateDocument: jest.fn().mockResolvedValue(
   128→            makeDatabaseSuccess(makeCollectionDocumentAssociation()),
   129→        ),
   130→        associateDocuments: jest.fn().mockResolvedValue(
   131→            makeDatabaseSuccess({ documents: [VERSION_ID_A] }),
   132→        ),
   133→        removeAllDocumentAssociations: jest.fn().mockResolvedValue(
   134→            makeDatabaseSuccess([makeCollectionDocumentPair()]),
   135→        ),
   136→        removeDocumentAssociation: jest.fn().mockResolvedValue(
   137→            makeDatabaseSuccess(null),
   138→        ),
   139→        removeUnassociatedDocuments: jest.fn().mockResolvedValue(
   140→            makeDatabaseSuccess([]),
   141→        ),
   142→        getCollectionDocuments: jest.fn().mockResolvedValue([
   143→            { sourceId: VERSION_ID_A, name: 'Doc A' },
   144→        ]),
   145→        linkToTerminology: jest.fn().mockResolvedValue(true),
   146→        unlinkFromTerminology: jest.fn().mockResolvedValue(true),
   147→        ...overrides,
   148→    } as unknown as jest.Mocked<CollectionRepository>;
   149→}
   150→
   151→/**
   152→ * Builds a jest-mocked TerminologyRepository with safe default return values.
   153→ */
   154→export function buildMockTerminologyRepository(
   155→    overrides: Partial<jest.Mocked<TerminologyRepository>> = {},
   156→): jest.Mocked<TerminologyRepository> {
   157→    return {
   158→        existTerminology: jest.fn().mockResolvedValue(true),
   159→        getTerminologyFromCollection: jest.fn().mockResolvedValue(TERMINOLOGY_ID_A),
   160→        countReferencesTo: jest.fn().mockResolvedValue(1),
   161→        deleteTerminologyFromDocument: jest.fn().mockResolvedValue(1),
   162→        ...overrides,
   163→    } as unknown as jest.Mocked<TerminologyRepository>;
   164→}
   165→
   166→/**
   167→ * Builds a jest-mocked TerminologyService.
   168→ */
   169→export function buildMockTerminologyService(
   170→    overrides: Partial<jest.Mocked<TerminologyService>> = {},
   171→): jest.Mocked<TerminologyService> {
   172→    return {
   173→        deleteTerminologyFromDocument: jest.fn().mockResolvedValue(1),
   174→        deleteTerminologyFromCollection: jest.fn().mockResolvedValue(1),
   175→        ...overrides,
   176→    } as unknown as jest.Mocked<TerminologyService>;
   177→}
   178→
   179→/**
   180→ * Builds a jest-mocked ApiService (enrichment).
   181→ */
   182→export function buildMockEnrichmentService(
   183→    overrides: Partial<jest.Mocked<ApiService>> = {},
   184→): jest.Mocked<ApiService> {
   185→    return {
   186→        triggerEnrichments: jest.fn().mockResolvedValue({
   187→            success: true,
   188→            transactionIds: ['tx-001'],
   189→        }),
   190→        ...overrides,
   191→    } as unknown as jest.Mocked<ApiService>;
   192→}
   193→
   194→/**
   195→ * Builds a jest-mocked AuditingService.
   196→ */
   197→export function buildMockAuditingService(
   198→    overrides: Partial<jest.Mocked<AuditingService>> = {},
   199→): jest.Mocked<AuditingService> {
   200→    return {
   201→        createMilestone: jest.fn().mockResolvedValue(AUDIT_ID),
   202→        complete: jest.fn().mockResolvedValue(undefined),
   203→        fail: jest.fn().mockResolvedValue(undefined),
   204→        createRequestAudit: jest.fn().mockResolvedValue(AUDIT_ID),
   205→        getFullTrace: jest.fn().mockResolvedValue({ request: null, milestones: [] }),
   206→        getStats: jest.fn().mockResolvedValue({}),
   207→        ...overrides,
   208→    } as unknown as jest.Mocked<AuditingService>;
   209→}
   210→
   211→/**
   212→ * Builds a jest-mocked AsyncTransactionHelper.
   213→ *
   214→ * By default `executeAsync` immediately invokes the supplied operation so that
   215→ * tests can assert on what the operation callback does without needing any
   216→ * async-flush utilities.
   217→ */
   218→export function buildMockAsyncTransactionHelper(
   219→    overrides: Partial<jest.Mocked<AsyncTransactionHelper>> = {},
   220→): jest.Mocked<AsyncTransactionHelper> {
   221→    return {
   222→        executeAsync: jest.fn().mockImplementation(
   223→            async (_auditId: string, operation: () => Promise<any>) => {
   224→                await operation();
   225→                return { success: true, transactionId: _auditId };
   226→            },
   227→        ),
   228→        executeAsyncTracked: jest.fn().mockImplementation(
   229→            async (_auditId: string, operation: () => Promise<any>) => {
   230→                return operation();
   231→            },
   232→        ),
   233→        ...overrides,
   234→    } as unknown as jest.Mocked<AsyncTransactionHelper>;
   235→}
   236→
   237→// ---------------------------------------------------------------------------
   238→// Suite factory helpers
   239→// ---------------------------------------------------------------------------
   240→
   241→/**
   242→ * Constructs a fully-wired CollectionService with all dependencies mocked.
   243→ * Callers may pass per-dependency overrides to customise specific mock
   244→ * behaviours for a given test scenario.
   245→ */
   246→export function buildServiceSuite(opts: {
   247→    collectionRepo?: Partial<jest.Mocked<CollectionRepository>>;
   248→    terminologyRepo?: Partial<jest.Mocked<TerminologyRepository>>;
   249→    terminologyService?: Partial<jest.Mocked<TerminologyService>>;
   250→    enrichmentService?: Partial<jest.Mocked<ApiService>>;
   251→    auditingService?: Partial<jest.Mocked<AuditingService>>;
   252→} = {}) {
   253→    const collectionRepo = buildMockCollectionRepository(opts.collectionRepo ?? {});
   254→    const terminologyRepo = buildMockTerminologyRepository(opts.terminologyRepo ?? {});
   255→    const terminologyService = buildMockTerminologyService(opts.terminologyService ?? {});
   256→    const enrichmentService = buildMockEnrichmentService(opts.enrichmentService ?? {});
   257→    const auditingService = buildMockAuditingService(opts.auditingService ?? {});
   258→
   259→    const service = new CollectionService(
   260→        collectionRepo,
   261→        auditingService,
   262→        terminologyRepo,
   263→        terminologyService,
   264→        enrichmentService,
   265→        collectionRepo, // collectionRepo is injected twice (collectionRepository & collectionRepo)
   266→    );
   267→
   268→    return { service, collectionRepo, terminologyRepo, terminologyService, enrichmentService, auditingService };
   269→}
   270→
   271→/**
   272→ * Constructs a fully-wired CollectionController with all dependencies mocked.
   273→ */
   274→export function buildControllerSuite(opts: {
   275→    collectionService?: Partial<jest.Mocked<CollectionService>>;
   276→    asyncHelper?: Partial<jest.Mocked<AsyncTransactionHelper>>;
   277→} = {}) {
   278→    const collectionServiceMock = {
   279→        getAllCollections: jest.fn().mockResolvedValue(makeDatabaseSuccess([makeSystemCollection()])),
   280→        addCollection: jest.fn().mockResolvedValue(makeDatabaseSuccess({ sourceId: COLLECTION_ID_A })),
   281→        updateName: jest.fn().mockResolvedValue(makeDatabaseSuccess({ sourceId: COLLECTION_ID_A, terminologyId: TERMINOLOGY_ID_A })),
   282→        deleteCollection: jest.fn().mockResolvedValue(makeDatabaseSuccess({ count: 1 })),
   283→        linkToTerminology: jest.fn().mockResolvedValue(true),
   284→        unlinkFromTerminology: jest.fn().mockResolvedValue(true),
   285→        associateDocument: jest.fn().mockResolvedValue(makeDatabaseSuccess(makeCollectionDocumentAssociation())),
   286→        unassociateDocument: jest.fn().mockResolvedValue(makeDatabaseSuccess(null)),
   287→        setDocuments: jest.fn().mockResolvedValue(makeDatabaseSuccess({ documents: [VERSION_ID_A] })),
   288→        ...opts.collectionService,
   289→    } as unknown as jest.Mocked<CollectionService>;
   290→
   291→    const asyncHelper = buildMockAsyncTransactionHelper(opts.asyncHelper ?? {});
   292→
   293→    const controller = new CollectionController(collectionServiceMock, asyncHelper);
   294→
   295→    return { controller, collectionServiceMock, asyncHelper };
   296→}
