     1→/**
     2→ * @file test-helpers.ts
     3→ *
     4→ * Shared constants, fixture factories, and mock-builder helpers for the
     5→ * document module test suites.
     6→ *
     7→ * Nothing in this file is specific to a single test — it is the single
     8→ * source of truth for all test data in the document module.
     9→ */
    10→
    11→import { DocumentController } from '../document.controller';
    12→import { DocumentService } from '../document.service';
    13→
    14→// ---------------------------------------------------------------------------
    15→// Constants
    16→// ---------------------------------------------------------------------------
    17→
    18→export const VERSION_ID = 'version-id-111';
    19→export const SOURCE_ID = 'source-id-doc-aaa';
    20→export const DOC_NAME = 'Test Document';
    21→export const DOC_NAME_UPDATED = 'Updated Document';
    22→export const DOC_TYPE_PDF = 'pdf';
    23→export const DOC_TYPE_MD = 'md';
    24→export const COLLECTION_ID_A = 'collection-id-aaa';
    25→export const COLLECTION_ID_B = 'collection-id-bbb';
    26→export const TERMINOLOGY_ID_A = 'terminology-id-aaa';
    27→export const TERMINOLOGY_ID_B = 'terminology-id-bbb';
    28→export const AUDIT_ID = 'audit-tx-001';
    29→export const DATA_ID = 'data-id-uuid-001';
    30→export const ERROR_REPO_FAILED = 'repository operation failed';
    31→
    32→// ---------------------------------------------------------------------------
    33→// DatabaseResult factories
    34→// ---------------------------------------------------------------------------
    35→
    36→export function makeDatabaseSuccess<T>(data?: T): { success: true; data: T } {
    37→    return { success: true, data: data as T };
    38→}
    39→
    40→export function makeDatabaseError(message = ERROR_REPO_FAILED): { success: false; error: string } {
    41→    return { success: false, error: message };
