   151→        deleteDocument: jest.fn().mockResolvedValue(makeDatabaseSuccess(makeDeleteDocumentResult())),
   152→        hasDocument: jest.fn().mockResolvedValue(makeDatabaseSuccess({ exists: true })),
   153→        getDocumentBySourceId: jest.fn().mockResolvedValue(makeDatabaseSuccess(makeDocumentNode())),
   154→        getDocumentsByCollection: jest.fn().mockResolvedValue(makeDatabaseSuccess([makeDocumentNode()])),
