   208→}
   209→
   210→export function buildMockDocumentService(overrides: Record<string, jest.Mock> = {}) {
   211→    return {
   212→        allDocuments: jest.fn().mockResolvedValue(makeDatabaseSuccess([makeDocumentNode()])),
   213→        updateDocumentName: jest.fn().mockResolvedValue(makeDatabaseSuccess({ versionId: VERSION_ID, name: DOC_NAME_UPDATED })),
   214→        updateDocumentsName: jest.fn().mockResolvedValue(undefined),
   215→        addDocument: jest.fn().mockResolvedValue(undefined),
   216→        deleteDocument: jest.fn().mockResolvedValue(makeDatabaseSuccess(makeDeleteDocumentResult())),
   217→        hasDocument: jest.fn().mockResolvedValue(makeDatabaseSuccess({ exists: true })),
   218→        getDocumentBySourceId: jest.fn().mockResolvedValue(makeDatabaseSuccess(makeDocumentNode())),
   219→        getDocumentsByCollection: jest.fn().mockResolvedValue(makeDatabaseSuccess([makeDocumentNode()])),
   220→        getDocumentsByCollections: jest.fn().mockResolvedValue(makeDatabaseSuccess([makeDocumentNode()])),
