   225→
   226→/**
   227→ * Builds a mock AsyncTransactionHelper whose executeAsync immediately invokes
   228→ * the passed operation and returns a standard success payload.
   229→ * The mock can be inspected with expect(asyncHelper.executeAsync).toHaveBeenCalledWith(...)
   230→ */
   231→export function buildMockAsyncTransactionHelper(overrides: Record<string, jest.Mock> = {}) {
   232→    return {
   233→        executeAsync: jest.fn().mockImplementation(async (auditId: string, operation: () => Promise<any>) => {
   234→            await operation();
   235→            return { success: true, transactionId: auditId };
   236→        }),
   237→        ...overrides,
   238→    };
   239→}
   240→
   241→// ---------------------------------------------------------------------------
   242→// Suite-level factory functions
   243→// ---------------------------------------------------------------------------
   244→
   245→type ServiceSuiteOverrides = {
   246→    documentRepo?: Partial<ReturnType<typeof buildMockDocumentRepository>>;
   247→    pdfService?: Partial<ReturnType<typeof buildMockPdfService>>;
   248→    markdownService?: Partial<ReturnType<typeof buildMockMarkdownService>>;
   249→    analysisService?: Partial<ReturnType<typeof buildMockAnalysisService>>;
   250→    textService?: Partial<ReturnType<typeof buildMockTextService>>;
   251→    collectionService?: Partial<ReturnType<typeof buildMockCollectionService>>;
   252→    enrichmentService?: Partial<ReturnType<typeof buildMockEnrichmentApiService>>;
   253→    terminologyService?: Partial<ReturnType<typeof buildMockTerminologyService>>;
   254→};
   255→
   256→/**
   257→ * Builds a fully-wired DocumentService with all dependencies mocked.
   258→ * Pass override maps to customise individual mock methods per test.
   259→ */
   260→export function buildServiceSuite(overrides: ServiceSuiteOverrides = {}) {
   261→    const documentRepo = { ...buildMockDocumentRepository(), ...overrides.documentRepo };
   262→    const pdfService = { ...buildMockPdfService(), ...overrides.pdfService };
   263→    const markdownService = { ...buildMockMarkdownService(), ...overrides.markdownService };
   264→    const analysisService = { ...buildMockAnalysisService(), ...overrides.analysisService };
   265→    const textService = { ...buildMockTextService(), ...overrides.textService };
   266→    const collectionService = { ...buildMockCollectionService(), ...overrides.collectionService };
   267→    const enrichmentService = { ...buildMockEnrichmentApiService(), ...overrides.enrichmentService };
   268→    const terminologyService = { ...buildMockTerminologyService(), ...overrides.terminologyService };
   269→
   270→    const service = new DocumentService(
   271→        pdfService as any,
   272→        analysisService as any,
   273→        documentRepo as any,
