     1→/**
     2→ * @file concurrency.spec.ts
     3→ *
     4→ * Unit tests for createBreather (concurrency utility).
     5→ *
     6→ * Jest fake timers are used so tests execute instantly without real delays.
     7→ * The spy-on-setTimeout approach verifies the correct delay value is passed
     8→ * without needing to wait for the timer to fire in real time.
     9→ */
    10→
    11→import { createBreather } from '../concurrency';
    12→
    13→describe('createBreather', () => {
    14→    afterEach(() => {
    15→        jest.useRealTimers();
    16→        jest.restoreAllMocks();
    17→    });
    18→
    19→    // -----------------------------------------------------------------------
    20→    it('should return a function', () => {
    21→        const breather = createBreather();
    22→
    23→        expect(typeof breather).toBe('function');
    24→    });
    25→
    26→    it('should return an async function that returns a Promise', () => {
    27→        const breather = createBreather();
    28→
    29→        const result = breather();
    30→
    31→        expect(result).toBeInstanceOf(Promise);
    32→    });
    33→
    34→    it('should call setTimeout with the default delay of 50ms when no argument is provided', () => {
    35→        jest.useFakeTimers();
    36→        const setTimeoutSpy = jest.spyOn(global, 'setTimeout');
    37→
    38→        const breather = createBreather();
    39→        breather();
    40→
    41→        expect(setTimeoutSpy).toHaveBeenCalledWith(expect.any(Function), 50);
    42→    });
    43→
    44→    it('should call setTimeout with the provided delay in milliseconds', () => {
    45→        jest.useFakeTimers();
    46→        const setTimeoutSpy = jest.spyOn(global, 'setTimeout');
    47→
    48→        const breather = createBreather(200);
    49→        breather();
    50→
    51→        expect(setTimeoutSpy).toHaveBeenCalledWith(expect.any(Function), 200);
    52→    });
    53→
    54→    it('should resolve the returned Promise after the timer fires', async () => {
    55→        jest.useFakeTimers();
    56→
    57→        const breather = createBreather(100);
    58→        const promise = breather();
    59→
    60→        // Advance timers to fire the setTimeout callback
    61→        jest.advanceTimersByTime(100);
    62→
    63→        // If the promise does not resolve this will timeout the test
    64→        await expect(promise).resolves.toBeUndefined();
    65→    });
    66→
    67→    it('should resolve independently on each successive call', async () => {
    68→        jest.useFakeTimers();
    69→
    70→        const breather = createBreather(50);
    71→        const p1 = breather();
    72→        const p2 = breather();
    73→
    74→        jest.advanceTimersByTime(50);
    75→
    76→        await expect(p1).resolves.toBeUndefined();
    77→        await expect(p2).resolves.toBeUndefined();
    78→    });
    79→});
    80→

